// // This module decrements the 2-bit binary counter on the positive edge of the clock and sets the output to 7 when the reset signal is high.
module binary_counter_2bit
(
    input clk,
    input rst,
    output reg [1:0] count
);

always @(posedge clk) begin
    if (rst) begin
        count <= 2'd0;
    end else begin
        count <= count + 2'd1;
    end
end

endmodule
